import{c as n,Q as t,j as r,g as l}from"./chunks/framework.hhGiamYR.js";const m=JSON.parse('{"title":"论李维 I.8 — 指控与谣言","description":"","frontmatter":{"date":"2026-06-13T00:00:00.000Z","source":"machiavelli/discourses/book1/08-第八章","title":"论李维 I.8 — 指控与谣言"},"headers":[],"relativePath":"fragments/2026-06-13.md","filePath":"fragments/2026-06-13.md"}'),a={name:"fragments/2026-06-13.md"};function s(o,e,u,p,c,i){return t(),r("div",null,[...e[0]||(e[0]=[l("p",null,'……曼利乌斯·卡皮托利努斯站在平民中间，说他拯救了朱庇特神庙、功绩不逊于卡米卢斯，那些给法兰克人的财宝被私吞了——他没有证据，他不说名字，他只是让愤怒在人群里发酵。独裁官把他叫到面前问"谁拿了那些财宝"，他说"你们本来就知道的事，何必再说"。然后被关进牢房。我知道这个故事的每一个角落——因为我也在牢房里待过，我也被人问过"你说啊，你的同谋是谁"。区别是曼利乌斯是造谣者，而我是被造谣的人。但那种"不必再说"的傲慢，我在吊绳上体会过。不是我的傲慢——是问我那些问题的人的。',-1),l("hr",null,null,-1),l("p",null,'罗马人有一个制度：每个人都可以公开指控一个公民，但必须提供确凿的证据和证人。指控在法庭上，谣言在街道上——这就是共和国和乱世的区别。当我读到"谣言既不需要证人，也不必由任何特定的人群坐实其真伪"的时候，我把书合上了。我在想佛罗伦萨——不，我在想我自己。1513年2月，有人把我名字写在博斯科利名单上。没有一个人出来指控我——只是在集市上和街廊里互相传。然后我就被吊了六次。',-1),l("hr",null,null,-1),l("p",null,"李维讲了一个道理——我把它翻译成了现代语言。他说：谣言只会激怒公民，却不会让他们受到惩罚。激怒的人更想报复，对于伤害他们的流言蜚语只有仇恨没有惧怕。这个句子太准了，准到我后悔不是我自己写的。我笔下的佛罗伦萨人在梅塞尔·乔万尼打了败仗之后——不管是不是收了卢卡人的钱——他们要的不是真相，是愤怒的出口。没有指控的制度，就没有真相的制度。只有愤怒的制度。",-1),l("hr",null,null,-1),l("p",null,'……而我现在坐在这里写《论李维》的评注，写罗马的制度多么完善。罗马的制度。在佛罗伦萨呢？我亲眼看着乔万尼·圭齐阿尔迪尼——梅塞尔·乔万尼，不是弗朗切斯科——被谣言逼到绝境。他的敌人从谣言里受益，而且他们没有风险。因为在这个共和国里，没有人会问"你的证据呢"。他要求首领处置他，想还自己清白，但没有那个制度。这个故事我不知讲了多少遍，每次讲到这里都有一种奇怪的感觉——我既是在写他，也是在写我自己。只不过他死在了谣言里，我活了下来……然后继续写书给那些不想读的人看。',-1),l("hr",null,null,-1),l("p",null,'一个人仅靠这些谣言，就可以成就自己的大业——这句话是我写的，但我每次重读都觉得有点冷。因为这不是理论。我在佛罗伦萨见过太多人，站在人民一边，把人民对某些公民强人的成见称为言之有据——然后人民就成了他们的朋友。这手法简单得令人绝望：不需要证人，不需要证据，不需要承担任何后果。你说一句话，愤怒自己会走路。曼利乌斯在罗马试过一次，失败了。在佛罗伦萨，每天都有曼利乌斯站在街角——唯一的问题是，他们没有一个独裁官把他们叫到面前问"你的证据呢"。我们从罗马学到了战争，学到了法律，学到了扩疆——唯独没学到怎么防谣言。然后共和国就覆灭了。',-1)])])}const f=n(a,[["render",s]]);export{m as __pageData,f as default};
